import React, { useState, useEffect } from 'react';
import axios from 'axios';
import { 
  LogIn, UserPlus, ShieldCheck, FileText, CheckCircle, 
  X, LogOut, ArrowRight, Activity, Upload, Clock, HelpCircle, LayoutDashboard, Users, MessageCircle, AlertCircle
} from 'lucide-react';

const Login = () => {
  const [view, setView] = useState('landing'); 
  const [activeTab, setActiveTab] = useState('services'); 
  const [formData, setFormData] = useState({ name: '', email: '', password: '' });
  const [userRequests, setUserRequests] = useState([]); 
  const [adminRequests, setAdminRequests] = useState([]); // FOR ADMIN TABLE
  const [userCount, setUserCount] = useState(0); // FOR ADMIN STATS
  const [showModal, setShowModal] = useState(false);
  const [showSupport, setShowSupport] = useState(false); 
  const [selectedFileName, setSelectedFileName] = useState("");

  // --- ADMIN: FETCH REAL DATABASE DATA ---
  const syncAdminDashboard = async () => {
    try {
      const res = await axios.get('http://localhost:5000/api/admin/all-data');
      setAdminRequests(res.data.requests); // REAL APPLICATIONS
      setUserCount(res.data.usersCount); // REAL USER COUNT
    } catch (e) { console.error("Admin Sync Error", e); }
  };

  const loadUserData = async (id) => {
    try {
      const res = await axios.get(`http://localhost:5000/api/requests/user/${id}`);
      setUserRequests(res.data);
    } catch (e) { console.error(e); }
  };

  useEffect(() => {
    const token = localStorage.getItem('token');
    const role = localStorage.getItem('userRole');
    const userId = localStorage.getItem('userId');
    if (token) {
      if (role === 'admin') {
        setView('admin-dashboard');
        syncAdminDashboard();
      } else {
        setView('dashboard');
        loadUserData(userId);
      }
    }
  }, []);

  // --- AUTH ---
  const handleAuth = async (e) => {
    e.preventDefault();
    const mode = (view === 'admin-login' || view === 'login') ? 'login' : 'register';
    try {
      const res = await axios.post(`http://localhost:5000/api/auth/${mode}`, formData);
      if (mode === 'login') {
        localStorage.setItem('token', res.data.token);
        localStorage.setItem('userRole', res.data.user.role);
        localStorage.setItem('userId', res.data.user._id);
        localStorage.setItem('userName', res.data.user.name);
        
        if (res.data.user.role === 'admin') {
          setView('admin-dashboard');
          await syncAdminDashboard();
        } else {
          setView('dashboard');
          await loadUserData(res.data.user._id);
        }
      } else {
        alert("Registration Successful!");
        setView('login');
      }
    } catch (err) { alert("Authentication Failed. Check Server."); }
  };

  // --- ADMIN ACTIONS (The Amazon/Facebook Style Moderation) ---
  const handleStatusChange = async (id, newStatus) => {
    try {
      await axios.put(`http://localhost:5000/api/admin/status/${id}`, { status: newStatus });
      alert(`✅ Updated to ${newStatus}`);
      syncAdminDashboard(); // Refresh the list from DB
    } catch (e) { alert("Update Failed"); }
  };

  const handleSupportSubmit = async (e) => {
    e.preventDefault();
    await axios.post('http://localhost:5000/api/support/send', {
      userId: localStorage.getItem('userId'),
      userName: localStorage.getItem('userName'),
      message: e.target[0].value
    });
    alert("Support Ticket Sent!");
    setShowSupport(false);
  };

  const handleFileUpload = async () => {
    try {
      const [fh] = await window.showOpenFilePicker();
      const f = await fh.getFile();
      setSelectedFileName(f.name);
    } catch (e) {}
  };

  const handleSubmission = async (e) => {
    e.preventDefault();
    await axios.post('http://localhost:5000/api/requests/submit', {
      userId: localStorage.getItem('userId'),
      userName: localStorage.getItem('userName'),
      type: e.target[0].value,
      licenseNumber: e.target[1].value,
      documentUrl: selectedFileName || "verification_doc.pdf"
    });
    setShowModal(false);
    loadUserData(localStorage.getItem('userId'));
    setActiveTab('tracking');
  };

  // ==========================================
  // VIEW: LANDING & AUTH
  // ==========================================
  if (['landing', 'login', 'register', 'admin-login'].includes(view)) {
    return (
      <div className="min-h-screen bg-slate-50 flex flex-col items-center justify-center p-6 text-center">
        {view === 'landing' ? (
          <div className="max-w-4xl w-full animate-in fade-in duration-700">
            <h1 className="text-5xl font-black text-slate-900 mb-12 italic uppercase">QUAD SOLUTIONS</h1>
            <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
              <div onClick={() => setView('register')} className="bg-white p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-600 cursor-pointer transition text-left group">
                <UserPlus className="text-blue-600 mb-6 group-hover:scale-110 transition" size={32} />
                <h2 className="text-2xl font-black">New Providers</h2>
                <div className="text-blue-600 font-bold mt-2">Get Started <ArrowRight className="inline ml-2" /></div>
              </div>
              <div onClick={() => setView('login')} className="bg-slate-900 text-white p-10 rounded-[3rem] shadow-xl border-2 border-transparent hover:border-blue-400 cursor-pointer transition text-left group">
                <LogIn className="text-blue-400 mb-6 group-hover:scale-110 transition" size={32} />
                <h2 className="text-2xl font-black">Existing Clients</h2>
                <div className="text-blue-400 font-bold mt-2">Sign In <ArrowRight className="inline ml-2" /></div>
              </div>
            </div>
            <footer className="mt-20"><button onClick={() => setView('admin-login')} className="bg-white border px-6 py-2 rounded-full text-[10px] font-black uppercase text-slate-300 hover:text-blue-600 transition tracking-widest"><ShieldCheck className="inline mr-2" size={14}/> Internal Admin Access</button></footer>
          </div>
        ) : (
          <div className="w-full max-w-md bg-white p-10 rounded-[3rem] shadow-2xl relative">
            <button onClick={() => setView('landing')} className="absolute top-8 right-8 text-slate-300 font-bold">Back</button>
            <h2 className="text-3xl font-black mb-8 italic uppercase underline decoration-blue-600 underline-offset-8 decoration-4">{view.replace('-', ' ')}</h2>
            <form onSubmit={handleAuth} className="space-y-4 text-left">
              {view === 'register' && <input type="text" placeholder="Full Name" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" onChange={e => setFormData({...formData, name: e.target.value})} required />}
              <input type="email" placeholder="Email" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" onChange={e => setFormData({...formData, email: e.target.value})} required />
              <input type="password" placeholder="Password" className="w-full p-4 bg-slate-50 rounded-2xl outline-none font-bold" onChange={e => setFormData({...formData, password: e.target.value})} required />
              <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-xl hover:bg-blue-700 transition">Continue</button>
            </form>
          </div>
        )}
      </div>
    );
  }

  // ==========================================
  // VIEW: ADMIN PANEL (LIVE MODERATION)
  // ==========================================
  if (view === 'admin-dashboard') {
    return (
      <div className="min-h-screen bg-slate-950 text-white">
        <nav className="p-6 border-b border-slate-900 flex justify-between bg-black/40 backdrop-blur-md sticky top-0 z-50">
          <div className="flex items-center gap-3"><LayoutDashboard className="text-blue-500" /><h1 className="text-xl font-black tracking-widest text-blue-500 uppercase italic">Admin Console</h1></div>
          <button onClick={() => {localStorage.clear(); window.location.reload();}} className="bg-red-600 text-white px-6 py-2 rounded-xl font-black shadow-lg">Logout</button>
        </nav>
        <main className="p-10 max-w-7xl mx-auto w-full">
           <div className="grid grid-cols-1 md:grid-cols-3 gap-8 mb-16">
              <div className="bg-slate-900 p-10 rounded-[2.5rem] border border-slate-800 shadow-2xl"><p className="text-slate-500 font-black text-xs uppercase tracking-widest">Total Providers</p><h4 className="text-6xl font-black">{userCount}</h4></div>
              <div className="bg-slate-900 p-10 rounded-[2.5rem] border border-slate-800 border-l-4 border-l-yellow-500 shadow-2xl"><p className="text-slate-500 font-black text-xs uppercase tracking-widest">Global Requests</p><h4 className="text-6xl font-black text-yellow-500">{adminRequests.length}</h4></div>
              <div className="bg-slate-900 p-10 rounded-[2.5rem] border border-slate-800 border-l-4 border-l-green-500 shadow-2xl"><p className="text-slate-500 font-black text-xs uppercase tracking-widest">Approved</p><h4 className="text-6xl font-black text-green-500">{adminRequests.filter(r => r.status === 'Approved').length}</h4></div>
           </div>
           
           <div className="bg-slate-900 rounded-[3rem] border border-slate-800 overflow-hidden shadow-2xl">
              <div className="p-8 border-b border-slate-800 bg-black/20 flex justify-between items-center">
                  <h2 className="text-2xl font-black italic uppercase tracking-tighter flex items-center gap-3"><FileText className="text-blue-500"/> Application Registry</h2>
                  <span className="text-[10px] font-black text-slate-500 uppercase bg-slate-800 px-4 py-2 rounded-xl border border-slate-700">Real-Time Sync Active</span>
              </div>
              <table className="w-full text-left">
                <thead className="bg-black/40 text-slate-500 text-[10px] font-black uppercase tracking-[0.2em] border-b border-slate-800">
                  <tr><th className="p-8">Provider Name</th><th className="p-8">Service Type</th><th className="p-8">File Name</th><th className="p-8">Status</th><th className="p-8 text-right">Moderation Actions</th></tr>
                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {adminRequests.map((req) => (
                    <tr key={req._id} className="hover:bg-blue-600/5 transition group">
                      <td className="p-8 font-black text-xs uppercase tracking-tighter">{req.userName}</td>
                      <td className="p-8 text-slate-400 font-bold text-xs uppercase italic">{req.type}</td>
                      <td className="p-8 text-blue-400 font-mono text-[10px] italic underline decoration-blue-500/30">{req.documentUrl}</td>
                      <td className="p-8">
                        <span className={`px-4 py-1 rounded-full text-[9px] font-black uppercase tracking-widest border ${req.status === 'Approved' ? 'bg-green-500/10 text-green-500 border-green-500/20' : (req.status === 'Rejected' ? 'bg-red-500/10 text-red-500 border-red-500/20' : 'bg-yellow-500/10 text-yellow-500 border-yellow-500/20')}`}>
                          {req.status}
                        </span>
                      </td>
                      <td className="p-8 text-right space-x-2">
                        <button onClick={() => handleStatusChange(req._id, 'Approved')} className="bg-green-600 text-white px-4 py-2 rounded-xl text-[9px] font-black hover:bg-green-500 transition shadow-lg shadow-green-900/20 uppercase tracking-widest">Approve</button>
                        <button onClick={() => handleStatusChange(req._id, 'Pending')} className="bg-yellow-500 text-black px-4 py-2 rounded-xl text-[9px] font-black hover:bg-yellow-400 transition shadow-lg shadow-yellow-900/20 uppercase tracking-widest">Pending</button>
                        <button onClick={() => handleStatusChange(req._id, 'Rejected')} className="bg-red-600/20 text-red-500 px-4 py-2 rounded-xl text-[9px] font-black border border-red-500/20 hover:bg-red-600 hover:text-white transition uppercase tracking-widest">Reject</button>
                      </td>
                    </tr>
                  ))}
                  {adminRequests.length === 0 && (
                    <tr><td colSpan="5" className="p-20 text-center text-slate-500 font-black uppercase italic tracking-widest">No Provider Applications found in Database</td></tr>
                  )}
                </tbody>
              </table>
           </div>
        </main>
      </div>
    );
  }

  // ==========================================
  // VIEW: USER DASHBOARD
  // ==========================================
  return (
    <div className="min-h-screen bg-slate-50">
      <nav className="bg-white p-4 shadow-sm flex justify-between items-center sticky top-0 z-50">
        <h1 className="text-xl font-black text-blue-600 italic">QUAD SOLUTIONS</h1>
        <div className="flex gap-4">
           <button onClick={() => setActiveTab('services')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'services' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}>Services</button>
           <button onClick={() => setActiveTab('tracking')} className={`px-4 py-2 rounded-xl text-sm font-bold ${activeTab === 'tracking' ? 'bg-blue-600 text-white shadow-lg' : 'text-slate-400'}`}>My Trackings</button>
           <button onClick={() => {localStorage.clear(); window.location.reload();}} className="text-red-500 p-2"><LogOut size={20}/></button>
        </div>
      </nav>

      <main className="p-10 max-w-5xl mx-auto">
        {activeTab === 'services' ? (
          <div>
            <h2 className="text-3xl font-black mb-8 italic uppercase underline decoration-blue-600 underline-offset-8 decoration-4">Available Services</h2>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              {['Medical License Renewal', 'Insurance Enrollment', 'DEA Certification'].map(t => (
                <div key={t} className="bg-white p-8 rounded-[2.5rem] shadow-sm border border-slate-100 hover:shadow-xl transition group">
                   <div className="w-12 h-12 bg-blue-50 rounded-2xl flex items-center justify-center text-blue-600 mb-6 group-hover:bg-blue-600 group-hover:text-white transition-colors"><FileText/></div>
                   <h3 className="text-xl font-bold mb-4 tracking-tighter leading-tight italic uppercase">{t}</h3>
                   <button onClick={() => setShowModal(true)} className="w-full bg-slate-900 text-white py-3 rounded-xl text-[10px] font-black uppercase hover:bg-blue-600 transition tracking-widest">Apply Now</button>
                </div>
              ))}
            </div>
            <div className="mt-16 bg-blue-600 rounded-[3rem] p-12 text-white flex justify-between items-center shadow-2xl shadow-blue-200">
               <div><h3 className="text-2xl font-black italic uppercase tracking-tighter">Need Immediate Assistance?</h3><p className="font-medium opacity-80">Our support engineers are ready to help you.</p></div>
               <button onClick={() => setShowSupport(true)} className="bg-white text-blue-600 px-8 py-4 rounded-2xl font-black flex items-center gap-2 hover:scale-105 transition shadow-lg"><MessageCircle/> Contact Support</button>
            </div>
          </div>
        ) : (
          <div>
            <h2 className="text-3xl font-black mb-8 italic uppercase tracking-tighter">Application Status Tracking</h2>
            <div className="space-y-4">
               {userRequests.map((r, i) => (
                 <div key={r._id} className="bg-white p-8 rounded-[2.5rem] border border-slate-100 flex justify-between items-center shadow-sm hover:shadow-md transition group">
                    <div className="flex items-center gap-6">
                        <div className="w-14 h-14 bg-slate-900 rounded-2xl flex flex-col items-center justify-center text-white group-hover:bg-blue-600 transition-colors shadow-lg">
                            <span className="text-[8px] font-black opacity-40 uppercase">REQ</span>
                            <span className="text-lg font-black italic">0{i+1}</span>
                        </div>
                        <div><h3 className="text-xl font-black text-slate-800 uppercase tracking-tighter italic">{r.type}</h3><p className="text-slate-400 font-bold text-[9px] uppercase tracking-widest mt-1"><Clock size={10} className="inline mr-1"/> Submitted: {new Date(r.submittedDate).toLocaleDateString()}</p></div>
                    </div>
                    <div className={`px-6 py-2 rounded-full text-[10px] font-black uppercase tracking-widest ${r.status === 'Approved' ? 'bg-green-100 text-green-600' : 'bg-blue-100 text-blue-600'}`}>{r.status}</div>
                 </div>
               ))}
               {userRequests.length === 0 && <div className="p-20 text-center text-slate-300 font-black uppercase italic border-2 border-dashed rounded-[3rem]">No Active Applications in Registry</div>}
            </div>
          </div>
        )}
      </main>

      {/* SUPPORT MODAL */}
      {showSupport && (
        <div className="fixed inset-0 bg-slate-900/80 backdrop-blur-md flex items-center justify-center p-4 z-[200]">
          <div className="bg-white w-full max-w-md rounded-[3rem] p-10 animate-in zoom-in duration-200 shadow-2xl">
             <div className="flex justify-between items-center mb-6">
                <h2 className="text-2xl font-black text-blue-600 uppercase italic tracking-tighter">Support Ticket</h2>
                <button onClick={() => setShowSupport(false)}><X className="text-slate-300 hover:text-red-500 transition"/></button>
             </div>
             <form onSubmit={handleSupportSubmit} className="space-y-4">
                <p className="text-[10px] text-slate-400 font-black uppercase tracking-[0.2em] mb-2">Request Technical Help:</p>
                <textarea className="w-full p-6 bg-slate-50 rounded-2xl h-40 outline-none font-bold text-slate-700 border-none shadow-inner" placeholder="Explain your issue here..." required></textarea>
                <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-xl shadow-blue-100 uppercase tracking-widest">Dispatch Ticket</button>
             </form>
          </div>
        </div>
      )}

      {/* SUBMISSION MODAL */}
      {showModal && (
        <div className="fixed inset-0 bg-slate-900/60 backdrop-blur-sm flex items-center justify-center p-4 z-[100]">
          <div className="bg-white w-full max-w-md rounded-[3rem] p-10 shadow-2xl animate-in zoom-in duration-200">
            <h2 className="text-2xl font-black mb-8 text-blue-600 uppercase italic tracking-tighter decoration-blue-600 underline underline-offset-4">New Request</h2>
            <form onSubmit={handleSubmission} className="space-y-4">
              <select className="w-full p-4 bg-slate-50 rounded-2xl font-bold border-none outline-none shadow-sm"><option>Medical License</option><option>Insurance Enrollment</option><option>DEA Certification</option></select>
              <input type="text" placeholder="License / NPI Number" className="w-full p-4 bg-slate-50 rounded-2xl font-bold border-none outline-none shadow-sm" required />
              <div onClick={handleFileUpload} className="p-10 bg-blue-50 border-2 border-dashed border-blue-200 rounded-[2rem] cursor-pointer text-center group hover:bg-blue-100 transition">
                <Upload className="mx-auto text-blue-400 mb-2 group-hover:scale-110 transition" size={32}/>
                <p className="text-[10px] font-black uppercase text-blue-600 tracking-tighter italic">{selectedFileName ? `READY: ${selectedFileName}` : "Select System Document"}</p>
              </div>
              <button className="w-full bg-blue-600 text-white py-4 rounded-2xl font-black shadow-xl shadow-blue-100 transition mt-4 uppercase tracking-widest italic">Submit Application</button>
              <button onClick={() => setShowModal(false)} type="button" className="w-full mt-2 text-slate-300 font-bold hover:text-red-500 transition text-[10px] uppercase">Discard</button>
            </form>
          </div>
        </div>
      )}
    </div>
  );
};

export default Login;
